export const AdminActionBody = zod.object({
  reportId: zod.string(),
  actionType: zod.enum(["BAN_USER", "DELETE_POST", "WARN_USER", "DISMISS"]),
  notes: zod.string().optional(),
});

export const AdminActionResponse = zod.object({
  success: zod.boolean(),
  message: zod.string(),
});

/**
 * @summary Get all users with flags (admin only)
 */
export const GetAdminUsersQueryParams = zod.object({
  flagged: zod.coerce.boolean().optional(),
});

export const GetAdminUsersResponse = zod.object({
  users: zod.array(
    zod.object({
      id: zod.string(),
      name: zod.string(),
      email: zod.string(),
      collegeId: zod.string(),
      college: zod
        .object({
          id: zod.string(),
          name: zod.string(),
          domain: zod.string(),
          location: zod.string(),
        })
        .nullish(),
      isActive: zod.boolean(),
      isBanned: zod.boolean(),
      reportCount: zod.number(),
      createdAt: zod.coerce.date(),
    }),
  ),
});
